class AllOne:
    def __init__(self):
        self.key_cnt = {}
        # doubly-linked list: sentinel head (min side) and tail (max side)
        # each node: {'cnt': int, 'keys': set, 'prev': node, 'next': node}
        self.head = {'cnt': 0, 'keys': set(), 'prev': None, 'next': None}
        self.tail = {'cnt': 0, 'keys': set(), 'prev': None, 'next': None}
        self.head['next'] = self.tail
        self.tail['prev'] = self.head
        self.cnt_node = {}  # cnt -> node

    def _insert_after(self, node, new_cnt):
        new_node = {'cnt': new_cnt, 'keys': set(), 'prev': node, 'next': node['next']}
        node['next']['prev'] = new_node
        node['next'] = new_node
        self.cnt_node[new_cnt] = new_node
        return new_node

    def _remove_node(self, node):
        node['prev']['next'] = node['next']
        node['next']['prev'] = node['prev']
        del self.cnt_node[node['cnt']]

    def inc(self, key):
        old_cnt = self.key_cnt.get(key, 0)
        new_cnt = old_cnt + 1
        self.key_cnt[key] = new_cnt
        if new_cnt not in self.cnt_node:
            if old_cnt == 0:
                self._insert_after(self.head, new_cnt)
            else:
                self._insert_after(self.cnt_node[old_cnt], new_cnt)
        self.cnt_node[new_cnt]['keys'].add(key)
        if old_cnt > 0:
            old_node = self.cnt_node[old_cnt]
            old_node['keys'].discard(key)
            if not old_node['keys']:
                self._remove_node(old_node)

    def dec(self, key):
        old_cnt = self.key_cnt[key]
        new_cnt = old_cnt - 1
        if new_cnt == 0:
            del self.key_cnt[key]
        else:
            self.key_cnt[key] = new_cnt
            if new_cnt not in self.cnt_node:
                self._insert_after(self.cnt_node[old_cnt]['prev'], new_cnt)
            self.cnt_node[new_cnt]['keys'].add(key)
        old_node = self.cnt_node[old_cnt]
        old_node['keys'].discard(key)
        if not old_node['keys']:
            self._remove_node(old_node)

    def getMaxKey(self):
        node = self.tail['prev']
        if node is self.head:
            return ''
        return min(node['keys'])

    def getMinKey(self):
        node = self.head['next']
        if node is self.tail:
            return ''
        return min(node['keys'])

