class AllOne {
    constructor() {
        this.keyCnt = new Map();
        this.head = { cnt: 0, keys: new Set(), prev: null, next: null };
        this.tail = { cnt: 0, keys: new Set(), prev: null, next: null };
        this.head.next = this.tail;
        this.tail.prev = this.head;
        this.cntNode = new Map();
    }
    _insertAfter(node, newCnt) {
        const nn = { cnt: newCnt, keys: new Set(), prev: node, next: node.next };
        node.next.prev = nn;
        node.next = nn;
        this.cntNode.set(newCnt, nn);
        return nn;
    }
    _removeNode(node) {
        node.prev.next = node.next;
        node.next.prev = node.prev;
        this.cntNode.delete(node.cnt);
    }
    inc(key) {
        const oldCnt = this.keyCnt.get(key) || 0;
        const newCnt = oldCnt + 1;
        this.keyCnt.set(key, newCnt);
        if (!this.cntNode.has(newCnt)) {
            const anchor = oldCnt === 0 ? this.head : this.cntNode.get(oldCnt);
            this._insertAfter(anchor, newCnt);
        }
        this.cntNode.get(newCnt).keys.add(key);
        if (oldCnt > 0) {
            const oldNode = this.cntNode.get(oldCnt);
            oldNode.keys.delete(key);
            if (oldNode.keys.size === 0) this._removeNode(oldNode);
        }
    }
    dec(key) {
        const oldCnt = this.keyCnt.get(key);
        const newCnt = oldCnt - 1;
        if (newCnt === 0) {
            this.keyCnt.delete(key);
        } else {
            this.keyCnt.set(key, newCnt);
            if (!this.cntNode.has(newCnt)) {
                this._insertAfter(this.cntNode.get(oldCnt).prev, newCnt);
            }
            this.cntNode.get(newCnt).keys.add(key);
        }
        const oldNode = this.cntNode.get(oldCnt);
        oldNode.keys.delete(key);
        if (oldNode.keys.size === 0) this._removeNode(oldNode);
    }
    _minOfSet(s) {
        let best = null;
        for (const k of s) if (best === null || k < best) best = k;
        return best;
    }
    getMaxKey() {
        const node = this.tail.prev;
        if (node === this.head) return '';
        return this._minOfSet(node.keys);
    }
    getMinKey() {
        const node = this.head.next;
        if (node === this.tail) return '';
        return this._minOfSet(node.keys);
    }
}
